// Cướp toàn bộ dữ liệu của Não AI đẩy xuống
const data = $input.first().json.output;

// 1. Chế tạo 1 cái máy nặn UUID thủ công bằng Toán Học (Lách luật chặn Crypto)
function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// 2. Map Icon ngẫu nhiên để không bị App Crash
const iconMap = { 'Food': 0xe56c, 'Transport': 0xe1d4, 'Shopping': 0xf4d8, 'Bills': 0xef63, 'Salary': 0xe917, 'Invest': 0xe6e1, 'Rent': 0xf521, 'Other': 0xe838 };
const colorMap = { 'Food': 0xFFFF5722, 'Transport': 0xFF2196F3, 'Shopping': 0xFFE91E63, 'Bills': 0xFF9C27B0, 'Salary': 0xFF4CAF50, 'Invest': 0xFF009688, 'Rent': 0xFF3F51B5, 'Other': 0xFF9E9E9E };
const cat = data.categoryName || 'Other';
const now = new Date().toISOString();

// Gom trọn gói đầy đủ gửi cho Supabase
return [{
  json: {
    sync_id:              uuid(),  // Gọi hàm sinh mã 
    amount:               data.amount,
    is_expense:           data.isExpense,
    category_name:        cat,
    category_icon_code:   iconMap[cat] || iconMap['Other'],
    category_color_hex:   colorMap[cat] || colorMap['Other'],
    note:                 data.note || null,
    date:                 now,
    updated_at:           now,
    is_synced:            true,
    is_deleted:           false,
    replyMessage:         data.replyMessage,
  }
}];

