// 1. Máy hút dữ liệu: Lôi toàn bộ data chảy từ Supabase sang
const txns = $input.all(); 

let totalIncome = 0;
let totalExpense = 0;
let validTxnCount = 0; // Máy đếm số lượng giao dịch sống (Chưa xóa)
let historyStr = []; // Tờ giấy Note ghi lịch sử cho AI đọc

// 2. Chạy Vòng lặp Cộng trừ siêu tốc
txns.forEach((row) => {
    const data = row.json;

    // 👉 Màng lọc Giao dịch Khóa/Bị Xóa Mềm 
    // Thêm ngoặc nhọn {} để diệt hẳn cảnh báo gạch đỏ của hệ thống n8n
    if (data.is_deleted === true || data.isdeleted === true) {
        return; 
    }

    // Nếu lọt màng lưới (Giao dịch Sống), thì cộng 1 vào máy đếm
    validTxnCount++;

    const amount = Number(data.amount) || 0; 

    // Nếu là chi tiêu
    if (data.is_expense === true) {
        totalExpense += amount;
    } else {
        totalIncome += amount; // Thu nhập
    }

    // Tiện thể nặn ra 1 dòng Dễ đọc cho con LLM nó khỏi đọc JSON hại não
    const tBody = `- Ngày ${data.date ? data.date.substring(0,10) : 'N/A'}: [${data.category_name}] ${data.is_expense ? 'Chi' : 'Thu'} ${amount.toLocaleString('vi-VN')}vnđ (${data.note || 'Trống'})`;
    historyStr.push(tBody);
});

// 3. Đóng đai chốt sổ: Trả về Báo cáo Kế toán Gọn Băng Đẹp Đẽ!
return [{
  json: {
    tong_thu: totalIncome.toLocaleString('vi-VN') + " đ",
    tong_chi: totalExpense.toLocaleString('vi-VN') + " đ",
    so_du: (totalIncome - totalExpense).toLocaleString('vi-VN') + " đ",
    tong_so_giao_dich: validTxnCount, // Đổi sang hiển thị đúng số Giao dịch Sống
    kich_ban_lich_su: historyStr.join("\n") // Gộp thành đoạn văn bản xài dấu xuống dòng
  }
}];
